Pattern.Snippet:
```typescript
import { describe, it, expect, vi } from 'vitest';
import { OrderLifecycle } from './order-lifecycle.ts';
import type { OrderRepository, EventBus } from './ports.ts';

type OrderLifecycleContext = {
    sut: OrderLifecycle;
    saveOrder: ReturnType<typeof vi.fn>;
    publish: ReturnType<typeof vi.fn>;
};

function createOrderLifecycleContext(
    overrides: Partial<{
        saveOrder: OrderRepository['saveOrder'];
        publish: EventBus['publish'];
    }> = {},
): OrderLifecycleContext {
    const saveOrder = vi.fn(overrides.saveOrder ?? (async () => {}));
    const publish = vi.fn(overrides.publish ?? (() => {}));
    const sut = new OrderLifecycle({ saveOrder, publish });
    return { sut, saveOrder, publish };
}

describe('OrderLifecycle#settleCharge', () => {
    it('should persist order in PAID state and publish settled event', async () => {
        // purpose: side-effect contract ŌĆö repository write + emitted event
        // observation focus: persistence args + event payload, not pipeline internals

        // START_SETTLE_CHARGE_SETUP_CONTEXT
        const { sut, saveOrder, publish } = createOrderLifecycleContext();
        // END_SETTLE_CHARGE_SETUP_CONTEXT

        // START_SETTLE_CHARGE_TRIGGER
        await sut.settleCharge('ord-1');
        // END_SETTLE_CHARGE_TRIGGER

        // START_SETTLE_CHARGE_ASSERT_INTERACTIONS
        expect(saveOrder).toHaveBeenCalledWith({ id: 'ord-1', state: 'PAID' });
        expect(publish).toHaveBeenCalledWith({
            type: 'order.settled',
            detail: { orderId: 'ord-1' },
        });
        // END_SETTLE_CHARGE_ASSERT_INTERACTIONS
    });

    it('should not publish when persistence rejects', async () => {
        // contract: settled event is emitted ONLY after successful persistence
        // failure mode: a leaked event after a failed write would corrupt downstream consumers

        // START_SETTLE_CHARGE_FAILURE_SETUP_CONTEXT
        const { sut, publish } = createOrderLifecycleContext({
            saveOrder: async () => { throw new Error('db down'); },
        });
        // END_SETTLE_CHARGE_FAILURE_SETUP_CONTEXT

        // START_SETTLE_CHARGE_FAILURE_TRIGGER_AND_ASSERT
        await expect(sut.settleCharge('ord-1')).rejects.toThrow(/db down/);
        expect(publish).not.toHaveBeenCalled();
        // END_SETTLE_CHARGE_FAILURE_TRIGGER_AND_ASSERT
    });
});
```

```typescript
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { ScheduleRunner } from './schedule-runner.ts';

type ScheduleRunnerContext = {
    sut: ScheduleRunner;
    tick: (ms: number) => Promise;
};

describe('ScheduleRunner#runDueJobs', () => {
    let ctx: ScheduleRunnerContext;

    beforeEach(() => {
        vi.useFakeTimers();
        vi.setSystemTime(new Date('2026-01-01T00:00:00Z'));
        vi.stubEnv('SCHEDULE_TICK_MS', '1000');

        const sut = new ScheduleRunner();
        ctx = {
            sut,
            tick: (ms) => vi.advanceTimersByTimeAsync(ms),
        };
    });

    afterEach(() => {
        vi.useRealTimers();
        vi.unstubAllEnvs();
    });

    it('should fire a single job exactly once at its due time', async () => {
        // contract: a job scheduled at t+1000ms fires once at t+1000ms, not before, not twice

        // START_DUE_JOBS_SETUP_JOB
        const onFire = vi.fn();
        ctx.sut.schedule({ id: 'j1', dueAt: 1000, run: onFire });
        // END_DUE_JOBS_SETUP_JOB

        // START_DUE_JOBS_TRIGGER_TICK
        await ctx.tick(999);
        expect(onFire).not.toHaveBeenCalled();
        await ctx.tick(1);
        // END_DUE_JOBS_TRIGGER_TICK

        // START_DUE_JOBS_ASSERT_FIRED_ONCE
        expect(onFire).toHaveBeenCalledTimes(1);
        // END_DUE_JOBS_ASSERT_FIRED_ONCE
    });
});
```

```typescript
import { describe, it, expect, vi } from 'vitest';
import { CatalogSync } from './catalog-sync.ts';
import type { HttpRequest, CatalogStore } from './ports.ts';

type CatalogSyncContext = {
    sut: CatalogSync;
    httpRequest: ReturnType<typeof vi.fn>;
    store: CatalogStore;
};

function createCatalogSyncContext(
    overrides: Partial<{
        response: Awaited<ReturnType>;
        store: CatalogStore;
    }> = {},
): CatalogSyncContext {
    const httpRequest = vi.fn(async () =>
        overrides.response ?? { status: 200, body: { items: [] } },
    );
    const store = overrides.store ?? { replaceAll: vi.fn(async () => {}) };
    const sut = new CatalogSync({ httpRequest, store });
    return { sut, httpRequest, store };
}

describe('CatalogSync#pull', () => {
    it('should request the catalog endpoint and replace the store with normalized items', async () => {
        // observation focus: the URL pulled + the items written, not transport internals

        // START_PULL_SETUP_CONTEXT
        const { sut, httpRequest, store } = createCatalogSyncContext({
            response: {
                status: 200,
                body: { items: [{ id: '1', title: 'Keyboard ', stock: 3 }] },
            },
        });
        // END_PULL_SETUP_CONTEXT

        // START_PULL_TRIGGER
        await sut.pull();
        // END_PULL_TRIGGER

        // START_PULL_ASSERT_BOUNDARY
        expect(httpRequest).toHaveBeenCalledWith({ method: 'GET', url: '/v1/catalog' });
        expect(store.replaceAll).toHaveBeenCalledWith([
            { id: '1', title: 'Keyboard', stock: 3 },
        ]);
        // END_PULL_ASSERT_BOUNDARY
    });
});
```

Anti_Pattern.Bad:
```typescript
describe('OrderLifecycle', () => {
    let sut: OrderLifecycle;
    let saveOrder: ReturnType;
    let publish: ReturnType;
    let order: Order;
    let now: Date;

    beforeEach(() => {
        saveOrder = vi.fn(async () => {});
        publish = vi.fn();
        sut = new OrderLifecycle({ saveOrder, publish });
        order = { id: 'ord-1', state: 'PENDING' };
        now = new Date('2026-01-01T00:00:00Z');
    });

    it('persists order', async () => {
        await sut.settle(order, now);
        expect(saveOrder).toHaveBeenCalled();
    });

    it('persists order with discount', async () => {
        // The hook is wrong here ŌĆö the test needs a different SUT config and ends up reconstructing it.
        sut = new OrderLifecycle({ saveOrder, publish, discount: 0.1 });
        await sut.settle(order, now);
        expect(saveOrder).toHaveBeenCalled();
    });
});
```

Anti_Pattern.Good:
```typescript
// ONE context type + ONE factory for the file.
function createOrderLifecycleContext(overrides: Partial<{
    order: Order;
    now: Date;
    discount: number;
}> = {}) {
    const saveOrder = vi.fn(async () => {});
    const publish = vi.fn();
    const sut = new OrderLifecycle({ saveOrder, publish, discount: overrides.discount });
    const order = overrides.order ?? { id: 'ord-1', state: 'PENDING' };
    const now = overrides.now ?? new Date('2026-01-01T00:00:00Z');
    return { sut, saveOrder, publish, order, now };
}

describe('OrderLifecycle', () => {
    it('should persist order on settle', async () => {
        const { sut, saveOrder, order, now } = createOrderLifecycleContext();
        await sut.settle(order, now);
        expect(saveOrder).toHaveBeenCalledWith({ ...order, state: 'PAID' });
    });

    it('should apply discount before persisting', async () => {
        const { sut, saveOrder, order, now } = createOrderLifecycleContext({ discount: 0.1 });
        await sut.settle(order, now);
        expect(saveOrder).toHaveBeenCalledWith(expect.objectContaining({ discountApplied: 0.1 }));
    });
});
```

