// File: order-lifecycle.test.ts
function createOrderContextHappy() { /* ... */ }
function createOrderContextWithDiscount() { /* ... */ }
function createOrderContextFailing() { /* ... */ }

describe('OrderLifecycle', () => {
    it('persists', async () => {
        const { sut, saveOrder } = createOrderContextHappy();
        // ...
    });
    it('applies discount', async () => {
        const { sut, saveOrder } = createOrderContextWithDiscount();
        // ...
    });
    it('fails on db error', async () => {
        const { sut, publish } = createOrderContextFailing();
        // ...
    });
});
