Anti_Pattern.Good:
```typescript
function createOrderLifecycleContext(overrides: Partial<{
    discount: number;
    saveOrder: OrderRepository['saveOrder'];
}> = {}) {
    const saveOrder = vi.fn(overrides.saveOrder ?? (async () => {}));
    const publish = vi.fn();
    const sut = new OrderLifecycle({ saveOrder, publish, discount: overrides.discount });
    return { sut, saveOrder, publish };
}

// All three cases use the same factory; each passes the override that matters.
```

Anti_Pattern.Bad:
```typescript
import { CatalogSync } from './catalog-sync.ts';
import { httpClient } from './http-client.ts';

// Mocks an in-process module without a justification, even though `httpClient`
// could be passed via constructor.
vi.mock('./http-client.ts', () => ({
    httpClient: { get: vi.fn(async () => ({ status: 200, body: { items: [] } })) },
}));

describe('CatalogSync', () => {
    it('pulls catalog', async () => {
        const sut = new CatalogSync();
        await sut.pull();
        expect(httpClient.get).toHaveBeenCalled();
    });
});
```

Anti_Pattern.Good:
```typescript
// SUT exposes an injection seam: class CatalogSync { constructor(deps: { httpRequest: HttpRequest }) {} }
// Test uses the unified factory + a vi.fn() stub through the seam (see PT_DI_OVER_MOCK).
```

Anti_Pattern.Bad:
```typescript
// Run by the agent without operator review:
//   vitest --update
// Silently rewrites every changed snapshot, including ones that reflect a real regression.

it('renders module', () => {
    expect(renderModule(spec)).toMatchSnapshot();
});
```

Anti_Pattern.Good:
```typescript
it('should render module with the canonical header', () => {
    expect(renderModule(spec)).toMatchInlineSnapshot(`
        "/* generated module */
        export const value = 42;
        "
    `);
});
// For real changes the agent presents old vs new to the operator and waits for confirmation.
```

Anti_Pattern.Bad:
```typescript
// No imports ŌĆö relies on globals: true.
describe('Scheduler', () => {
    it('fires due jobs', async () => {
        vi.useFakeTimers();
        vi.setSystemTime(new Date('2026-01-01T00:00:00Z'));
        vi.stubEnv('TICK', '1000');
        // ...
        // No teardown ŌĆö fake timers and env leak into every later case in the file.
    });

    it('reads the wall clock', () => {
        expect(Date.now()).toBeGreaterThan(0); // Silently broken: still on fake timers.
    });
});
```

