Anti_Pattern.Bad:
```typescript
it('throws on bad input', async () => {
    try {
        await client.reserveStock('');
        expect.fail('should have thrown');
    } catch (e) {
        expect((e as Error).message).toContain('idempotency');
    }
});

it('reserves stock', async () => {
    // @ts-expect-error ŌĆö peeking into internals
    const before = client._inflightCount;
    await client.reserveStock('key-1');
    // @ts-expect-error
    const after = client._inflightCount;
    expect(after - before).toBe(1);
});
```

Anti_Pattern.Good:
```typescript
it('should reject when idempotency key is empty', async () => {
    await expect(client.reserveStock('')).rejects.toThrow(/idempotency.*empty|empty.*idempotency/i);
});

it('should expose reservation through the public lifecycle event', async () => {
    const events: ReservationEvent[] = [];
    client.on('reservation.requested', (e) => events.push(e));
    await client.reserveStock('key-1');
    expect(events).toEqual([expect.objectContaining({ idempotencyKey: 'key-1' })]);
});
```
